import re, json, sys, urllib.request, urllib.error, time

HEADERS = {
    'User-Agent': 'Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/***.***.***.*** Safari/537.36',
    'Accept-Language': 'en-US,en;q=0.9',
    'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
    'Referer': 'https://www.youtube.com/',
}

def fetch(url, extra_headers=None):
    req = urllib.request.Request(url)
    for k, v in HEADERS.items():
        req.add_header(k, v)
    if extra_headers:
        for k, v in extra_headers.items():
            req.add_header(k, v)
    with urllib.request.urlopen(req, timeout=15) as resp:
        return resp.read().decode('utf-8'), resp.getcode()

def get_caption_tracks(video_id):
    url = f'https://www.youtube.com/watch?v={video_id}'
    html, code = fetch(url)
    # Find ytInitialPlayerResponse
    m = re.search(r'"captionTracks":(\[.*?\])', html)
    if not m:
        return None
    tracks = json.loads(m.group(1))
    return tracks

def fetch_caption(base_url, lang='en'):
    # Add translation if needed
    url = base_url
    if '&fmt=' not in url:
        url += '&fmt=json3'
    try:
        data, code = fetch(url)
        if code == 200 and '<transcript>' in data or '"events"' in data:
            return data
    except urllib.error.HTTPError as e:
        return f'HTTP_{e.code}'
    except Exception as e:
        return f'ERR_{e}'
    return None

# Test with one video
vid = '8mY9wx_iMSU'
print(f'Testing {vid}...')
tracks = get_caption_tracks(vid)
if tracks:
    print(f'Found {len(tracks)} caption tracks:')
    for t in tracks:
        lang = t.get('languageCode', '?')
        kind = t.get('kind', '')
        translatable = t.get('isTranslatable', False)
        print(f'  - {lang} (kind={kind}, translatable={translatable})')

    # Try English first, then first translatable
    en_track = next((t for t in tracks if t.get('languageCode','').startswith('en')), None)
    trans_track = next((t for t in tracks if t.get('isTranslatable')), None)
    target = en_track or trans_track or tracks[0]

    if target:
        print(f'\nFetching caption for {target["languageCode"]}...')
        # Try without translation first
        result = fetch_caption(target['baseUrl'])
        if result and ('HTTP_4' in result or 'ERR_' in result):
            print(f'Direct fetch failed: {result}')
            # Try with translation to English
            if trans_track and target != en_track:
                trans_url = trans_track['baseUrl'] + '&tlang=en&fmt=json3'
                print(f'Trying translation...')
                result = fetch_caption(trans_url)

        if result and len(result) > 100 and 'HTTP_' not in result and 'ERR_' not in result:
            # Parse json3 format
            if '"events"' in result:
                try:
                    data = json.loads(result)
                    texts = []
                    for ev in data.get('events', []):
                        segs = ev.get('segs', [])
                        text = ''.join(s.get('utf8', '') for s in segs).strip()
                        if text:
                            texts.append(text)
                    full_text = ' '.join(texts)
                    print(f'SUCCESS! {len(full_text)} chars, {len(texts)} segments')
                    print(f'Preview: {full_text[:300]}')
                except:
                    print(f'Parse error, raw len={len(result)}')
                    print(f'Raw preview: {result[:300]}')
            elif '<text' in result:
                matches = re.findall(r'<text[^>]*>(.*?)</text>', result)
                full_text = ' '.join(matches[:10])
                print(f'XML format: {len(matches)} segments')
                print(f'Preview: {full_text[:300]}')
            else:
                print(f'Unknown format, len={len(result)}')
                print(f'Preview: {result[:300]}')
        else:
            print(f'Failed: {result[:200] if result else "empty"}')
else:
    print('No caption tracks found in page')

