        const text = await resp.text();
        return {
            status: resp.status,
            apiKey: apiKey?.substring(0, 10),
            clientVersion: clientVersion?.substring(0, 20),
            trackLang: trackName,
            responseLen: text.length,
            responseStart: text.substring(0, 300)
