// Construct get_transcript params manually using protobuf encoding
// YouTube transcript params format (protobuf):
// message {
//   message { string video_id = 1; } field1 = 1;
//   int32 track_index = 2;  // usually 0
// }

// Simple protobuf encoder for transcript params
function encodeTranscriptParams(videoId, trackIndex) {
    // Protobuf wire format encoding
    const bytes = [];
    // Field 1 (nested message): contains video_id
    const innerMsg = [];
    // Field 1 in inner message: video_id (wire type 2 = length-delimited)
    innerMsg.push(0x0a); // field 1, wire type 2
    innerMsg.push(videoId.length); // length
    for (let i = 0; i < videoId.length; i++) innerMsg.push(videoId.charCodeAt(i));

    // Wrap inner message in field 1
    bytes.push(0x0a); // field 1, wire type 2
    bytes.push(innerMsg.length);
    bytes.push(...innerMsg);

    // Field 2: track index (wire type 0 = varint)
    bytes.push(0x10); // field 2, wire type 0
    bytes.push(trackIndex); // value

    // Convert to base64
    const arr = new Uint8Array(bytes);
    let binary = '';
    for (let i = 0; i < arr.length; i++) binary += String.fromCharCode(arr[i]);
    return btoa(binary);
}

