import json, os, glob

sessions_dir = '/home/user/.gjc/agent/sessions/-tmp'
files = sorted(glob.glob(os.path.join(sessions_dir, '*.jsonl')), key=os.path.getmtime, reverse=True)

for f in files[:8]:
    fname = os.path.basename(f)
    size = os.path.getsize(f)
    user_msgs = []
    with open(f) as fh:
        for i, line in enumerate(fh, 1):
            try:
                d = json.loads(line)
                if d.get('type') == 'message' and d.get('message',{}).get('role') == 'user':
                    for c in d['message'].get('content', []):
                        if isinstance(c, dict) and c.get('type') == 'text':
                            t = c['text'][:80].replace(chr(10),' ')
                            user_msgs.append((i, t))
            except: pass
    if not user_msgs:
        continue
    print(f'{fname} ({size//1024}KB, {len(user_msgs)} msgs):')
    for ln, t in user_msgs:
        print(f'  L{ln}: {t}')
    print()
